(function initEmbeddedBackgrounds(globalScope) {
  "use strict";

  function encodeBase64(input) {
    if (typeof btoa === "function") {
      return btoa(unescape(encodeURIComponent(input)));
    }
    if (typeof Buffer !== "undefined") {
      return Buffer.from(input, "utf8").toString("base64");
    }
    throw new Error("Base64 encoder is unavailable in this environment.");
  }

  function svgToDataUri(svg) {
    return "data:image/svg+xml;base64," + encodeBase64(svg);
  }

  function buildSvg(config) {
    return (
      '<svg xmlns="http://www.w3.org/2000/svg" width="1080" height="1440" viewBox="0 0 1080 1440">' +
      "<defs>" +
      '<linearGradient id="g1" x1="0%" y1="0%" x2="100%" y2="100%">' +
      '<stop offset="0%" stop-color="' + config.c1 + '"/>' +
      '<stop offset="100%" stop-color="' + config.c2 + '"/>' +
      "</linearGradient>" +
      '<radialGradient id="g2" cx="85%" cy="15%" r="60%">' +
      '<stop offset="0%" stop-color="' + config.glow + '" stop-opacity="0.9"/>' +
      '<stop offset="100%" stop-color="' + config.glow + '" stop-opacity="0"/>' +
      "</radialGradient>" +
      "</defs>" +
      '<rect width="1080" height="1440" fill="url(#g1)"/>' +
      '<rect width="1080" height="1440" fill="url(#g2)"/>' +
      '<circle cx="160" cy="180" r="190" fill="' + config.dot + '" fill-opacity="0.18"/>' +
      '<circle cx="910" cy="1260" r="240" fill="' + config.dot + '" fill-opacity="0.16"/>' +
      '<path d="M130 820 C300 730, 400 980, 620 900 C760 845, 820 1020, 980 950 L980 1200 L130 1200Z" fill="' + config.wave + '" fill-opacity="0.15"/>' +
      "</svg>"
    );
  }

  var xiaoxing = {
    cover: svgToDataUri(
      buildSvg({
        c1: "#1C6E8C",
        c2: "#F4982B",
        glow: "#FFEAA8",
        dot: "#FFFFFF",
        wave: "#0A3447"
      })
    ),
    pages: {
      auto: svgToDataUri(
        buildSvg({
          c1: "#315E86",
          c2: "#ED9960",
          glow: "#FFE9CC",
          dot: "#FDF5E8",
          wave: "#183248"
        })
      ),
      list: svgToDataUri(
        buildSvg({
          c1: "#2B7784",
          c2: "#E2A857",
          glow: "#FFF1C9",
          dot: "#E8FFFB",
          wave: "#174D52"
        })
      ),
      tag: svgToDataUri(
        buildSvg({
          c1: "#235E87",
          c2: "#E97C43",
          glow: "#FFDEC2",
          dot: "#FFFFFF",
          wave: "#143854"
        })
      ),
      compare: svgToDataUri(
        buildSvg({
          c1: "#375A92",
          c2: "#E06D5F",
          glow: "#FEE0D7",
          dot: "#FFFFFF",
          wave: "#162B58"
        })
      )
    }
  };

  var xiaoxingLabBase = "data:image/jpeg;base64,";

  var rifuBase = "data:image/jpeg;base64,";

  var banxiaBase = "data:image/jpeg;base64,";

  globalScope.XHS_EMBEDDED_BACKGROUNDS = {
    xiaoxing: xiaoxing,
    xiaoxing_lab: {
      cover: xiaoxingLabBase,
      pages: {
        auto: xiaoxingLabBase,
        list: xiaoxingLabBase,
        tag: xiaoxingLabBase,
        compare: xiaoxingLabBase
      }
    },
    rifu: {
      cover: rifuBase,
      pages: {
        auto: rifuBase,
        list: rifuBase,
        tag: rifuBase,
        compare: rifuBase
      }
    },
    banxia: {
      cover: banxiaBase,
      pages: {
        auto: banxiaBase,
        list: banxiaBase,
        tag: banxiaBase,
        compare: banxiaBase
      }
    }
  };
})(typeof window !== "undefined" ? window : globalThis);
